import{_ as e,o as a,c as r,a3 as l}from"./chunks/framework.d0TBG0Rg.js";const p=JSON.parse('{"title":"HX-Pjsk-Gateway","description":"Project Sekai 高性能 Web 查询网关，提供网页端 PJSK 查分、查榜服务。","frontmatter":{"title":"HX-Pjsk-Gateway","description":"Project Sekai 高性能 Web 查询网关，提供网页端 PJSK 查分、查榜服务。"},"headers":[],"relativePath":"projects/hx-pjsk-gateway.md","filePath":"projects/hx-pjsk-gateway.md"}'),o={name:"projects/hx-pjsk-gateway.md"};function i(n,t,s,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="hx-pjsk-gateway-pjsk-web-bridge" tabindex="-1">HX-Pjsk-Gateway (PJSK Web Bridge) <a class="header-anchor" href="#hx-pjsk-gateway-pjsk-web-bridge" aria-label="Permalink to &quot;HX-Pjsk-Gateway (PJSK Web Bridge)&quot;">​</a></h1><blockquote><p>Mizuki PJSK 查分终端 — 基于 Web 的无缝鉴权与数据可视化网关，作为 OneBot v11 / Napcat 机器人的前端延伸，让玩家通过网页端优雅、直观地获取《Project Sekai》游戏数据。</p></blockquote><br><div style="text-align:center;margin:20px 0;"><a href="https://pjsk.mizuki.top" target="_blank" class="mzk-button mzk-button--primary"> 🚀 访问 pjsk.mizuki.top </a></div><br><h2 id="🛠️-技术栈" tabindex="-1">🛠️ 技术栈 <a class="header-anchor" href="#🛠️-技术栈" aria-label="Permalink to &quot;🛠️ 技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:left;">技术选型</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>前端</strong></td><td style="text-align:left;">React + Vite + TypeScript + Zustand</td></tr><tr><td style="text-align:left;"><strong>中间层</strong></td><td style="text-align:left;">FastAPI (Python + uvloop)</td></tr><tr><td style="text-align:left;"><strong>数据引擎</strong></td><td style="text-align:left;">Haruki / Sakura Client (OneBot v11)</td></tr><tr><td style="text-align:left;"><strong>鉴权节点</strong></td><td style="text-align:left;">NoneBot2</td></tr><tr><td style="text-align:left;"><strong>存储</strong></td><td style="text-align:left;">MySQL, Redis</td></tr></tbody></table><br><h2 id="🔄-核心流程" tabindex="-1">🔄 核心流程 <a class="header-anchor" href="#🔄-核心流程" aria-label="Permalink to &quot;🔄 核心流程&quot;">​</a></h2><h3 id="_1-qq-强身份认证" tabindex="-1">1. QQ 强身份认证 <a class="header-anchor" href="#_1-qq-强身份认证" aria-label="Permalink to &quot;1. QQ 强身份认证&quot;">​</a></h3><p>彻底弃用传统账号密码，利用 QQ 实现设备与游戏数据的双重绑定。用户发送验证码至 Bot，通过 SSE 实时推送 Token，无缝继承已有 Suite 数据。</p><h3 id="_2-异步-echo-查询" tabindex="-1">2. 异步 Echo 查询 <a class="header-anchor" href="#_2-异步-echo-查询" aria-label="Permalink to &quot;2. 异步 Echo 查询&quot;">​</a></h3><p>利用 OneBot 协议的 <code>echo</code> 字段解决单点 WebSocket 多并发上下文错乱问题。请求挂起为 <code>asyncio.Future</code>，收到对应返回包后精确唤醒，同时支持 15 秒软超时降级。</p><h3 id="_3-图片旁路极速渲染" tabindex="-1">3. 图片旁路极速渲染 <a class="header-anchor" href="#_3-图片旁路极速渲染" aria-label="Permalink to &quot;3. 图片旁路极速渲染&quot;">​</a></h3><p>拦截 Haruki 响应中的本地图片绝对路径，实时转码为 WebP 格式（体积缩减约 80%），通过浏览器原生缓存实现秒开。</p><br><h2 id="🛡️-纵深防御" tabindex="-1">🛡️ 纵深防御 <a class="header-anchor" href="#🛡️-纵深防御" aria-label="Permalink to &quot;🛡️ 纵深防御&quot;">​</a></h2><ul><li>物理隔离风控：高频查询不连接腾讯服务器，由本地 Haruki 节点消化 OneBot 数据包，实现 0 冻结风险</li><li>设备级熔断：单账户上限 5 台设备的 LRU 淘汰队列</li><li>边缘安全：CF Tunnel 隐藏源站 + Turnstile 人机验证 + 雷池 WAF</li></ul><br><div style="text-align:center;margin:30px 0;"><a href="https://pjsk.mizuki.top" target="_blank" class="mzk-button mzk-button--primary"> 🌐 打开 HX-Pjsk-Gateway </a></div>',20)])])}const b=e(o,[["render",i]]);export{p as __pageData,b as default};
